            return Err(VfsError::NotFound);
        }

        let dev_id = DeviceId::new(7, 256 * partition + number);
        Ok(NodeOpsMux::File(Device::new(
            self.fs.clone(),
            NodeType::BlockDevice,
            dev_id,
            Arc::new(r#loop::LoopDevice::new(number, dev_id)),
        )))
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

