pub enum AsyncIoOwner {
    Tid(Pid),
    Pid(Pid),
    Pgrp(Pid),
}

#[derive(Clone, Copy)]
pub struct AsyncIoState {
    pub owner: AsyncIoOwner,
    pub signal: u8,
}

impl Default for AsyncIoState {
    fn default() -> Self {
        Self {
            owner: AsyncIoOwner::Pid(0),
